const raw = $input.first().json;
const body = raw.body || raw;
const notification = body.notification || {};
const subject = notification.subject || {};
const vuln = subject.vulnerability || {};
const component = subject.component || {};
const affectedProjects = subject.affectedProjects || [];
const vulnId = (vuln.vulnId || 'VULN-UNKNOWN').toString().trim();
const group = (notification.group || '').toString();
const title = (notification.title || 'Dependency-Track Alert').toString();
const content = (notification.content || '').toString();
const severity = (vuln.severity || 'UNKNOWN').toString();
const compName = [component.group, component.name].filter(Boolean).join('/') || component.name || 'unknown';
const compVersion = (component.version || '').toString();
const projectNames = affectedProjects.map(function(p) { return (p.name || '') + (p.version ? ' @ ' + p.version : ''); }).filter(Boolean);
const stream = (typeof process !== 'undefined' && process.env && process.env.ZULIP_DEPENDENCY_TRACK_STREAM) ? process.env.ZULIP_DEPENDENCY_TRACK_STREAM : 'security';
const topic = vulnId;
let md = '**' + title + '**\n';
md += '**Vulnerability:** ' + vulnId + ' | **Severity:** ' + severity + '\n';
md += '**Component:** ' + compName + (compVersion ? ' `' + compVersion + '`' : '') + '\n';
if (projectNames.length) { md += '**Affected projects:** ' + projectNames.join(', ') + '\n'; }
md += '\n' + content;
return [{ json: { zulip_stream: stream, zulip_topic: topic, zulip_content: md, vuln_id: vulnId, result: 'parsed' } }];
